import React, { useState, useEffect, useCallback } from "react";
import "./index.css";
import { api } from "./api";

// ─── Utilities ────────────────────────────────────────────────────────────────

function initials(name = "") {
  return name
    .split(" ")
    .map((p) => p[0])
    .join("")
    .slice(0, 2)
    .toUpperCase();
}

function fmtDate(iso = "") {
  if (!iso) return "—";
  const d = new Date(iso + "T12:00:00");
  return d.toLocaleDateString("en-US", {
    weekday: "short",
    month: "short",
    day: "numeric",
  });
}

function fmtDateTime(iso = "") {
  if (!iso) return "—";
  // Parse ISO string and display in the browser's local timezone
  const d = new Date(iso);
  return d.toLocaleString("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit",
    hour12: true,
    timeZoneName: "short",
  });
}

// ─── Toast ────────────────────────────────────────────────────────────────────

function useToast() {
  const [toasts, setToasts] = useState([]);
  const toast = useCallback((msg, type = "success") => {
    const id = Date.now();
    setToasts((t) => [...t, { id, msg, type }]);
    setTimeout(() => setToasts((t) => t.filter((x) => x.id !== id)), 3500);
  }, []);
  return { toasts, toast };
}

function ToastContainer({ toasts }) {
  return (
    <div className="toast-container">
      {toasts.map((t) => (
        <div key={t.id} className={`toast ${t.type}`}>
          <span>{t.type === "success" ? "✓" : "✕"}</span>
          {t.msg}
        </div>
      ))}
    </div>
  );
}

// ─── Assign Driver Modal ──────────────────────────────────────────────────────

function AssignDriverModal({ request, drivers, onAssign, onClose }) {
  const [driverId, setDriverId] = useState("");
  const [pickupTime, setPickupTime] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const activeDrivers = drivers.filter((d) => d.active);

  async function submit() {
    if (!driverId) {
      setError("Please select a driver.");
      return;
    }
    if (!pickupTime) {
      setError("Please enter a pickup time.");
      return;
    }
    setLoading(true);
    setError("");
    try {
      const { request: updated } = await api.assignDriver(request.id, {
        driverId: Number(driverId),
        pickupTime,
      });
      onAssign(updated);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <h2>Assign driver</h2>
        <p className="modal-sub">
          Assigning to <strong>{request.rider_name}</strong>
          {request.rider_address ? ` · ${request.rider_address}` : ""}
        </p>

        {error && (
          <div
            style={{
              background: "var(--red-bg)",
              border: "1px solid rgba(248,113,113,0.3)",
              borderRadius: "var(--radius)",
              padding: "9px 12px",
              fontSize: 13,
              color: "var(--red)",
              marginBottom: 14,
            }}
          >
            {error}
          </div>
        )}

        <div className="field">
          <label>Driver *</label>
          <select
            value={driverId}
            onChange={(e) => setDriverId(e.target.value)}
          >
            <option value="">— Select a driver —</option>
            {activeDrivers.map((d) => (
              <option key={d.id} value={d.id}>
                {d.name}
                {d.phone ? ` (${d.phone})` : ""}
              </option>
            ))}
          </select>
          {activeDrivers.length === 0 && (
            <div style={{ fontSize: 12, color: "var(--amber)", marginTop: 6 }}>
              ⚠ No active drivers. Add drivers in the Drivers tab first.
            </div>
          )}
        </div>

        <div className="field">
          <label>Pickup time *</label>
          <input
            type="time"
            value={pickupTime}
            onChange={(e) => setPickupTime(e.target.value)}
            style={{ colorScheme: "dark" }}
          />
          <div style={{ fontSize: 11.5, color: "var(--text3)", marginTop: 5 }}>
            This will be included in the confirmation email to the rider.
          </div>
        </div>

        <div className="modal-footer">
          <button className="btn" onClick={onClose}>
            Cancel
          </button>
          <button
            className="btn btn-primary"
            onClick={submit}
            disabled={loading || activeDrivers.length === 0}
          >
            {loading ? "Assigning…" : "✓ Approve & assign"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Add/Edit Rider Modal ─────────────────────────────────────────────────────

function RiderModal({ rider, onSave, onClose }) {
  const isEdit = !!rider;
  const [form, setForm] = useState({
    name: rider?.name || "",
    email: rider?.email || "",
    phone: rider?.phone || "",
    address: rider?.address || "",
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const set = (k) => (e) => setForm((f) => ({ ...f, [k]: e.target.value }));

  async function submit() {
    if (!form.name.trim() || !form.email.trim()) {
      setError("Name and email are required.");
      return;
    }
    if (!isEdit && !form.address.trim()) {
      setError("Home address is required.");
      return;
    }
    setLoading(true);
    setError("");
    try {
      const fn = isEdit ? api.updateRider(rider.id, form) : api.addRider(form);
      const { rider: saved } = await fn;
      onSave(saved, isEdit);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <h2>{isEdit ? "Edit rider" : "Add a rider"}</h2>
        <p className="modal-sub">
          {isEdit
            ? `Update ${rider.name}'s information.`
            : "They'll receive Sunday ride prompts by email."}
        </p>
        {error && (
          <div
            style={{
              background: "var(--red-bg)",
              border: "1px solid rgba(248,113,113,0.3)",
              borderRadius: "var(--radius)",
              padding: "9px 12px",
              fontSize: 13,
              color: "var(--red)",
              marginBottom: 14,
            }}
          >
            {error}
          </div>
        )}
        <div className="field">
          <label>Full name *</label>
          <input
            value={form.name}
            onChange={set("name")}
            placeholder="e.g. Sarah Chen"
            autoFocus
          />
        </div>
        <div className="field">
          <label>Email address *</label>
          <input
            value={form.email}
            onChange={set("email")}
            type="email"
            placeholder="sarah@example.com"
          />
        </div>
        <div className="field">
          <label>Phone number (optional)</label>
          <input
            value={form.phone}
            onChange={set("phone")}
            type="tel"
            placeholder="+1 555 000 0000"
          />
        </div>
        <div className="field">
          <label>Home address *</label>
          <input
            value={form.address}
            onChange={set("address")}
            placeholder="e.g. 123 Main St, Springfield"
          />
        </div>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>
            Cancel
          </button>
          <button
            className="btn btn-primary"
            onClick={submit}
            disabled={loading}
          >
            {loading ? "Saving…" : isEdit ? "Save changes" : "Add rider"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Add/Edit Driver Modal ────────────────────────────────────────────────────

function DriverModal({ driver, onSave, onClose }) {
  const isEdit = !!driver;
  const [form, setForm] = useState({
    name: driver?.name || "",
    email: driver?.email || "",
    phone: driver?.phone || "",
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const set = (k) => (e) => setForm((f) => ({ ...f, [k]: e.target.value }));

  async function submit() {
    if (!form.name.trim() || !form.email.trim()) {
      setError("Name and email are required.");
      return;
    }
    setLoading(true);
    setError("");
    try {
      const fn = isEdit
        ? api.updateDriver(driver.id, form)
        : api.addDriver(form);
      const { driver: saved } = await fn;
      onSave(saved, isEdit);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <h2>{isEdit ? "Edit driver" : "Add a driver"}</h2>
        <p className="modal-sub">Drivers can be assigned to ride requests.</p>
        {error && (
          <div
            style={{
              background: "var(--red-bg)",
              border: "1px solid rgba(248,113,113,0.3)",
              borderRadius: "var(--radius)",
              padding: "9px 12px",
              fontSize: 13,
              color: "var(--red)",
              marginBottom: 14,
            }}
          >
            {error}
          </div>
        )}
        <div className="field">
          <label>Full name *</label>
          <input
            value={form.name}
            onChange={set("name")}
            placeholder="e.g. James Okafor"
            autoFocus
          />
        </div>
        <div className="field">
          <label>Email address *</label>
          <input
            value={form.email}
            onChange={set("email")}
            type="email"
            placeholder="james@example.com"
          />
        </div>
        <div className="field">
          <label>Phone (optional)</label>
          <input
            value={form.phone}
            onChange={set("phone")}
            placeholder="+1 555 000 0000"
          />
        </div>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>
            Cancel
          </button>
          <button
            className="btn btn-primary"
            onClick={submit}
            disabled={loading}
          >
            {loading ? "Saving…" : isEdit ? "Save changes" : "Add driver"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Requests tab ─────────────────────────────────────────────────────────────

function RequestsTab({ toast }) {
  const [requests, setRequests] = useState([]);
  const [drivers, setDrivers] = useState([]);
  const [week, setWeek] = useState("");
  const [loading, setLoading] = useState(true);
  const [assigning, setAssigning] = useState(null); // request being assigned

  async function load() {
    setLoading(true);
    try {
      const [r, d] = await Promise.all([
        api.getCurrentRequests(),
        api.getDrivers(),
      ]);
      setRequests(r.requests);
      setWeek(r.week);
      setDrivers(d.drivers);
    } catch (e) {
      toast(e.message, "error");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    load();
  }, []);

  async function setStatus(id, status) {
    try {
      await api.updateStatus(id, status);
      setRequests((rs) => rs.map((r) => (r.id === id ? { ...r, status } : r)));
      toast(
        status === "declined"
          ? "Request declined"
          : status === "pending"
            ? "Reset to pending"
            : "Updated",
      );
    } catch (e) {
      toast(e.message, "error");
    }
  }

  function handleAssigned(updated) {
    setRequests((rs) =>
      rs.map((r) => (r.id === updated.id ? { ...r, ...updated } : r)),
    );
    setAssigning(null);
    toast(`Driver assigned & rider notified ✓`);
  }

  async function remove(id) {
    if (!window.confirm("Remove this ride request?")) return;
    try {
      await api.deleteRequest(id);
      setRequests((rs) => rs.filter((r) => r.id !== id));
      toast("Request removed");
    } catch (e) {
      toast(e.message, "error");
    }
  }

  const pending = requests.filter((r) => r.status === "pending").length;
  const approved = requests.filter((r) => r.status === "approved").length;

  return (
    <div>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 18,
        }}
      >
        <div>
          <div
            style={{
              fontSize: 15,
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: 4,
            }}
          >
            This Sunday's requests
          </div>
          {week && (
            <div className="week-label">
              ⛪ CCB · {fmtDate(week)} &nbsp;·&nbsp; {requests.length} responded
              &nbsp;·&nbsp; {pending} pending &nbsp;·&nbsp; {approved} approved
            </div>
          )}
        </div>
        <button className="btn btn-sm" onClick={load}>
          ↺ Refresh
        </button>
      </div>

      <div className="card">
        {loading ? (
          <div className="empty">
            <div className="empty-sub">Loading…</div>
          </div>
        ) : requests.length === 0 ? (
          <div className="empty">
            <div className="empty-icon">⛪</div>
            <div className="empty-title">No responses yet</div>
            <div className="empty-sub">
              Riders will appear here after they reply to the Sunday
              notification.
            </div>
          </div>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Rider</th>
                <th>Address</th>
                <th>Responded</th>
                <th>Driver</th>
                <th>Pickup</th>
                <th>Status</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {requests.map((req) => (
                <tr key={req.id}>
                  <td>
                    <div className="name-cell">
                      <div className="avatar">{initials(req.rider_name)}</div>
                      <div>
                        <div style={{ fontWeight: 500 }}>{req.rider_name}</div>
                        <div style={{ fontSize: 11.5, color: "var(--text3)" }}>
                          {req.rider_email}
                        </div>
                      </div>
                    </div>
                  </td>
                  <td
                    style={{
                      color: "var(--text2)",
                      fontSize: 12.5,
                      maxWidth: 160,
                    }}
                  >
                    {req.rider_address || (
                      <span style={{ color: "var(--text3)" }}>—</span>
                    )}
                  </td>
                  <td style={{ color: "var(--text2)", fontSize: 12.5 }}>
                    {fmtDateTime(req.responded_at)}
                  </td>
                  <td style={{ fontSize: 13 }}>
                    {req.driver_name ? (
                      <span style={{ color: "var(--green)", fontWeight: 500 }}>
                        {req.driver_name}
                      </span>
                    ) : (
                      <span style={{ color: "var(--text3)" }}>Unassigned</span>
                    )}
                  </td>
                  <td
                    style={{
                      fontFamily: "var(--mono)",
                      fontSize: 12.5,
                      color: "var(--text2)",
                    }}
                  >
                    {req.pickup_time || (
                      <span style={{ color: "var(--text3)" }}>—</span>
                    )}
                  </td>
                  <td>
                    <span className={`badge badge-${req.status}`}>
                      <span className="dot" />
                      {req.status.charAt(0).toUpperCase() + req.status.slice(1)}
                    </span>
                  </td>
                  <td>
                    <div className="action-row">
                      <button
                        className="btn btn-sm btn-primary"
                        onClick={() => setAssigning(req)}
                        title={
                          req.status === "approved"
                            ? "Reassign driver"
                            : "Assign driver & approve"
                        }
                      >
                        {req.status === "approved"
                          ? "✎ Reassign"
                          : "✓ Assign driver"}
                      </button>
                      {req.status !== "declined" && (
                        <button
                          className="btn btn-sm btn-danger"
                          onClick={() => setStatus(req.id, "declined")}
                        >
                          ✕ Decline
                        </button>
                      )}
                      {req.status === "declined" && (
                        <button
                          className="btn btn-sm"
                          onClick={() => setStatus(req.id, "pending")}
                        >
                          Reset
                        </button>
                      )}
                      <button
                        className="btn btn-sm btn-danger btn-icon"
                        title="Delete"
                        onClick={() => remove(req.id)}
                      >
                        🗑
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {assigning && (
        <AssignDriverModal
          request={assigning}
          drivers={drivers}
          onAssign={handleAssigned}
          onClose={() => setAssigning(null)}
        />
      )}
    </div>
  );
}

// ─── Riders tab ───────────────────────────────────────────────────────────────

function RidersTab({ toast }) {
  const [riders, setRiders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [modal, setModal] = useState(null); // null | 'add' | rider object

  async function load() {
    setLoading(true);
    try {
      const { riders } = await api.getRiders();
      setRiders(riders);
    } catch (e) {
      toast(e.message, "error");
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    load();
  }, []);

  function handleSave(saved, isEdit) {
    if (isEdit)
      setRiders((rs) => rs.map((r) => (r.id === saved.id ? saved : r)));
    else setRiders((rs) => [...rs, saved]);
    setModal(null);
    toast(isEdit ? "Rider updated" : `${saved.name} added`);
  }

  async function toggleActive(rider) {
    try {
      const { rider: updated } = await api.updateRider(rider.id, {
        active: rider.active ? 0 : 1,
      });
      setRiders((rs) => rs.map((r) => (r.id === rider.id ? updated : r)));
      toast(
        updated.active
          ? `${rider.name} activated`
          : `${rider.name} deactivated`,
      );
    } catch (e) {
      toast(e.message, "error");
    }
  }

  async function deleteRider(id, name) {
    if (!window.confirm(`Remove ${name}?`)) return;
    try {
      await api.deleteRider(id);
      setRiders((rs) => rs.filter((r) => r.id !== id));
      toast(`${name} removed`);
    } catch (e) {
      toast(e.message, "error");
    }
  }

  return (
    <div>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 18,
        }}
      >
        <div>
          <div
            style={{
              fontSize: 15,
              fontWeight: 600,
              color: "var(--text)",
              marginBottom: 4,
            }}
          >
            All riders
          </div>
          <div style={{ fontSize: 12, color: "var(--text3)" }}>
            {riders.length} total · {riders.filter((r) => r.active).length}{" "}
            active
          </div>
        </div>
        <button className="btn btn-primary" onClick={() => setModal("add")}>
          + Add rider
        </button>
      </div>
      <div className="card">
        {loading ? (
          <div className="empty">
            <div className="empty-sub">Loading…</div>
          </div>
        ) : riders.length === 0 ? (
          <div className="empty">
            <div className="empty-icon">👤</div>
            <div className="empty-title">No riders yet</div>
            <div className="empty-sub">
              Add your first rider using the button above.
            </div>
          </div>
        ) : (
          <table>
            <thead>
              <tr>
                <th>Name</th>
                <th>Email</th>
                <th>Phone</th>
                <th>Address</th>
                <th>Status</th>
                <th>Added</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {riders.map((rider) => (
                <tr key={rider.id}>
                  <td>
                    <div className="name-cell">
                      <div className="avatar">{initials(rider.name)}</div>
                      <span style={{ fontWeight: 500 }}>{rider.name}</span>
                    </div>
                  </td>
                  <td
                    style={{
                      fontFamily: "var(--mono)",
                      fontSize: 12.5,
                      color: "var(--text2)",
                    }}
                  >
                    {rider.email}
                  </td>
                  <td
                    style={{
                      fontFamily: "var(--mono)",
                      fontSize: 12.5,
                      color: "var(--text2)",
                    }}
                  >
                    {rider.phone || (
                      <span style={{ color: "var(--text3)" }}>—</span>
                    )}
                  </td>
                  <td
                    style={{
                      fontSize: 12.5,
                      color: "var(--text2)",
                      maxWidth: 180,
                    }}
                  >
                    {rider.address || (
                      <span style={{ color: "var(--text3)" }}>—</span>
                    )}
                  </td>
                  <td>
                    <div
                      className="toggle-wrap"
                      onClick={() => toggleActive(rider)}
                    >
                      <div className={`toggle ${rider.active ? "on" : ""}`}>
                        <div className="toggle-thumb" />
                      </div>
                      <span
                        style={{
                          fontSize: 12.5,
                          color: rider.active ? "var(--green)" : "var(--text3)",
                        }}
                      >
                        {rider.active ? "Active" : "Inactive"}
                      </span>
                    </div>
                  </td>
                  <td style={{ color: "var(--text3)", fontSize: 12.5 }}>
                    {fmtDateTime(rider.created_at)}
                  </td>
                  <td>
                    <div className="action-row">
                      <button
                        className="btn btn-sm"
                        onClick={() => setModal(rider)}
                      >
                        Edit
                      </button>
                      <button
                        className="btn btn-sm btn-danger"
                        onClick={() => deleteRider(rider.id, rider.name)}
                      >
                        Remove
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
      {modal && (
        <RiderModal
          rider={modal === "add" ? null : modal}
          onSave={handleSave}
          onClose={() => setModal(null)}
        />
      )}
    </div>
  );
}

// ─── Drivers tab ──────────────────────────────────────────────────────────────

