      setDrivers((ds) => ds.map((d) => (d.id === saved.id ? saved : d)));
    else setDrivers((ds) => [...ds, saved]);
    setModal(null);
    toast(isEdit ? "Driver updated" : `${saved.name} added`);
  }

  async function toggleActive(driver) {
    try {
      const { driver: updated } = await api.updateDriver(driver.id, {
        active: driver.active ? 0 : 1,
      });
      setDrivers((ds) => ds.map((d) => (d.id === driver.id ? updated : d)));
      toast(
        updated.active
          ? `${driver.name} activated`
          : `${driver.name} deactivated`,
      );
    } catch (e) {
      toast(e.message, "error");
    }
  }

  async function deleteDriver(id, name) {
    if (!window.confirm(`Remove ${name}?`)) return;
    try {
      await api.deleteDriver(id);
      setDrivers((ds) => ds.filter((d) => d.id !== id));
      toast(`${name} removed`);
