                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ))
        )}
      </div>
      <div>
        <div
          style={{
            fontSize: 15,
            fontWeight: 600,
            color: "var(--text)",
            marginBottom: 18,
          }}
        >
          Notification history
        </div>
        <div className="card">
          {log.length === 0 ? (
            <div className="empty" style={{ padding: "28px 16px" }}>
              <div className="empty-sub">No notifications sent yet.</div>
            </div>
