// ─── Notify modal ─────────────────────────────────────────────────────────────

function NotifyModal({ onClose, onDone, toast }) {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState(null);

  async function send() {
    setLoading(true);
    try {
      const data = await api.sendNotification();
      setResult(data);
      toast(`Notification sent to ${data.sent} rider(s)`);
    } catch (e) {
      toast(e.message, "error");
      onClose();
    } finally {
      setLoading(false);
    }
  }

  if (result) {
    return (
      <div className="modal-overlay" onClick={onDone}>
        <div className="modal" onClick={(e) => e.stopPropagation()}>
          <h2>Notification sent ✓</h2>
          <p className="modal-sub">
            Asking riders about this Sunday's ride to CCB
          </p>
          <div style={{ maxHeight: 220, overflow: "auto" }}>
            {(result.results || []).map((r, i) => (
              <div
                key={i}
                style={{
                  display: "flex",
                  justifyContent: "space-between",
                  padding: "8px 0",
                  borderBottom: "1px solid var(--border)",
                  fontSize: 13,
                }}
              >
                <span>{r.rider}</span>
                <span
                  className={`badge badge-${r.status === "sent" ? "approved" : r.status === "demo" ? "demo" : "declined"}`}
                >
                  {r.status}
                </span>
              </div>
            ))}
          </div>
          <div className="modal-footer">
            <button className="btn btn-primary" onClick={onDone}>
              Done
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal" onClick={(e) => e.stopPropagation()}>
        <h2>Send ride notification</h2>
        <p className="modal-sub">
          Emails all active riders asking{" "}
          <em>"Do you want a ride to CCB this Sunday?"</em>
          <br />
          This normally fires automatically every Thursday at 5 PM.
        </p>
        <div className="modal-footer">
          <button className="btn" onClick={onClose}>
            Cancel
          </button>
          <button className="btn btn-primary" onClick={send} disabled={loading}>
            {loading ? "Sending…" : "🔔 Send to all riders"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Main App ─────────────────────────────────────────────────────────────────

const TABS = [
  { id: "requests", label: "Ride requests", icon: "🚗" },
  { id: "riders", label: "Riders", icon: "👥" },
  { id: "drivers", label: "Drivers", icon: "🧑‍✈️" },
  { id: "history", label: "History", icon: "📋" },
];

export default function App() {
  const [tab, setTab] = useState("requests");
  const [stats, setStats] = useState(null);
  const [showNotify, setShowNotify] = useState(false);
  const { toasts, toast } = useToast();

  async function loadStats() {
    try {
      const { stats } = await api.getStats();
      setStats(stats);
    } catch (_) {}
  }

  useEffect(() => {
    loadStats();
  }, [tab]);

  const pendingCount = stats?.thisWeek?.pending || 0;

  return (
    <div className="layout">
      <aside className="sidebar">
        <div className="sidebar-logo">
          <div className="logo-mark">
            <div className="logo-icon">⛪</div>
            <div>
              <div className="logo-text">CCB Rides</div>
              <div className="logo-sub">admin panel</div>
            </div>
          </div>
        </div>
        <nav className="sidebar-nav">
          {TABS.map((t) => (
            <button
              key={t.id}
              className={`nav-item ${tab === t.id ? "active" : ""}`}
              onClick={() => setTab(t.id)}
            >
              <span className="nav-icon">{t.icon}</span>
              <span>{t.label}</span>
              {t.id === "requests" && pendingCount > 0 && (
                <span className="nav-badge amber">{pendingCount}</span>
              )}
            </button>
          ))}
        </nav>
        <div className="sidebar-footer">
          <div className="schedule-chip">
            <div className="schedule-chip-label">Next ride</div>
            <div className="schedule-chip-value">
              {stats
                ? `Sunday, ${fmtDate(stats.thisWeek?.date)} · CCB`
                : "Sunday · CCB"}
              <span>Notification every Thursday at 5 PM</span>
            </div>
          </div>
        </div>
      </aside>

      <div className="main">
        <div className="topbar">
          <div>
            <div className="page-title">
              {TABS.find((t) => t.id === tab)?.label}
            </div>
            {stats && (
              <div className="page-sub">
                {stats.activeRiders} rider{stats.activeRiders !== 1 ? "s" : ""}{" "}
                · {stats.activeDrivers} driver
                {stats.activeDrivers !== 1 ? "s" : ""} · Sunday{" "}
                {fmtDate(stats.thisWeek?.date)}
              </div>
            )}
          </div>
          <div className="topbar-actions">
            <button
              className="btn notify-btn"
              onClick={() => setShowNotify(true)}
            >
              🔔 Send notification
            </button>
          </div>
        </div>

        <div className="content">
          {stats && (
            <div className="stats-grid">
              <div className="stat-card">
                <div className="stat-label">Riders</div>
                <div className="stat-value">{stats.totalRiders}</div>
                <div className="stat-sub">{stats.activeRiders} active</div>
              </div>
              <div className="stat-card">
                <div className="stat-label">Drivers</div>
                <div className="stat-value">{stats.totalDrivers}</div>
                <div className="stat-sub">{stats.activeDrivers} active</div>
              </div>
              <div className="stat-card">
                <div className="stat-label">This Sunday</div>
                <div className="stat-value" style={{ color: "var(--green)" }}>
                  {stats.thisWeek.approved}
                </div>
                <div className="stat-sub">
                  {stats.thisWeek.pending} pending · {stats.thisWeek.total}{" "}
                  total
                </div>
              </div>
              <div className="stat-card">
                <div className="stat-label">Last notified</div>
                <div className="stat-value" style={{ fontSize: 18 }}>
                  {stats.lastNotification
                    ? fmtDateTime(stats.lastNotification.sent_at)
                    : "—"}
                </div>
                <div className="stat-sub">
                  {stats.lastNotification
                    ? `${stats.lastNotification.rider_count} rider(s) notified`
                    : "Never sent"}
                </div>
              </div>
            </div>
          )}

          {tab === "requests" && <RequestsTab toast={toast} />}
          {tab === "riders" && <RidersTab toast={toast} />}
          {tab === "drivers" && <DriversTab toast={toast} />}
          {tab === "history" && <HistoryTab toast={toast} />}
        </div>
      </div>

      {showNotify && (
        <NotifyModal
          onClose={() => setShowNotify(false)}
          onDone={() => {
            setShowNotify(false);
            loadStats();
          }}
          toast={toast}
        />
      )}
      <ToastContainer toasts={toasts} />
    </div>
  );
}
